import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.locks.ReentrantLock;

/**
 * Represents an entry in the cache, holding the value and its expiration time.
 * @param <V> The type of the value stored in the cache.
 */
class CacheEntry<V> {
    V value;
    long expirationTimeMillis; // Absolute time in milliseconds when this entry expires

    public CacheEntry(V value, long ttlMillis) {
        this.value = value;
        this.expirationTimeMillis = System.currentTimeMillis() + ttlMillis;
    }

    public boolean isExpired() {
        return System.currentTimeMillis() > expirationTimeMillis;
    }
}

/**
 * Represents a node in the Doubly Linked List used for LRU eviction.
 * @param <K> The type of the key.
 * @param <V> The type of the value.
 */
class Node<K, V> {
    K key;
    CacheEntry<V> entry;
    Node<K, V> prev;
    Node<K, V> next;

    public Node(K key, CacheEntry<V> entry) {
        this.key = key;
        this.entry = entry;
    }
}

