     * @param capacity The maximum number of items the cache can hold. Must be > 0.
     * @param defaultTTLMillis The default time-to-live for cache entries in milliseconds. Must be > 0.
     */
    public LRUCache(int capacity, long defaultTTLMillis) {
        if (capacity <= 0) {
            throw new IllegalArgumentException("Cache capacity must be greater than 0.");
        }
        if (defaultTTLMillis <= 0) {
            throw new IllegalArgumentException("Default TTL must be greater than 0.");
        }
        this.capacity = capacity;
        this.defaultTTLMillis = defaultTTLMillis;
        this.cacheMap = new HashMap<>();
        this.head = null;
        this.tail = null;
